import json
import pymysql
from aws_lambda_powertools import Tracer, Logger

tracer = Tracer()
logger = Logger()

def lambda_handler(event, context):
    # Get search parameters from API Gateway event
    params = event["queryStringParameters"]
    
    # Build SQL query dynamically based on search parameters
    query = "SELECT * FROM products WHERE 1=1"
    for key, value in params.items():
        if value:
            query += f" AND {key} LIKE '%{value}%'"
    
    # Connect to RDS MySQL database using pymysql
    conn = pymysql.connect(host="your-rds-instance-endpoint", user="your-username", password="your-password", db="your-database")
    
    # Execute SQL query and return results as JSON
    with tracer.start_span("query_products"):
        cursor = conn.cursor()
        cursor.execute(query)
        results = cursor.fetchall()
        return json.dumps(results)